import React, { useState } from 'react'
import { useNavigate } from 'react-router-dom'
import { farmService } from '../../services/api'

const OwnerCreateFarm = () => {
  const [form, setForm] = useState({ farm_code: '', farm_name: '', location: '', area_hectare: '' })
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState('')
  const navigate = useNavigate()

  const handleChange = (e) => {
    const { name, value } = e.target
    setForm((f) => ({ ...f, [name]: value }))
  }

  const handleSubmit = async (e) => {
    e.preventDefault()
    setError('')
    setLoading(true)
    try {
      await farmService.createFarm(form)
      navigate('/owner/farms')
    } catch (err) {
      setError(err.response?.data?.message || err.message)
    } finally {
      setLoading(false)
    }
  }

  return (
    <div style={{ padding: 20, maxWidth: 720 }}>
      <h2>Tạo trại mới</h2>
      {error && <div className="alert alert-error">{error}</div>}

      <form onSubmit={handleSubmit}>
        <div className="form-group">
          <label>Mã trại</label>
          <input name="farm_code" value={form.farm_code} onChange={handleChange} required />
        </div>
        <div className="form-group">
          <label>Tên trại</label>
          <input name="farm_name" value={form.farm_name} onChange={handleChange} required />
        </div>
        <div className="form-group">
          <label>Địa điểm</label>
          <input name="location" value={form.location} onChange={handleChange} />
        </div>
        <div className="form-group">
          <label>Diện tích (ha)</label>
          <input name="area_hectare" value={form.area_hectare} onChange={handleChange} />
        </div>

        <div style={{ display: 'flex', gap: 8 }}>
          <button className="btn btn-primary" type="submit" disabled={loading}>{loading ? 'Đang tạo...' : 'Tạo trại'}</button>
          <button type="button" className="btn" onClick={() => navigate('/owner/farms')}>Hủy</button>
        </div>
      </form>
    </div>
  )
}

export default OwnerCreateFarm
